import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"Apps","description":"Explore the platform apps and first-party Sovereign apps included with the workspace runtime.","frontmatter":{"title":"Apps","description":"Explore the platform apps and first-party Sovereign apps included with the workspace runtime.","aside":false},"headers":[],"relativePath":"product/apps.md","filePath":"product/apps.md"}'),r={name:"product/apps.md"};function i(o,e,p,l,c,d){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="apps-in-a-sovereign-workspace" tabindex="-1">Apps in a Sovereign workspace <a class="header-anchor" href="#apps-in-a-sovereign-workspace" aria-label="Permalink to &quot;Apps in a Sovereign workspace&quot;">​</a></h1><p>Sovereign ships with the platform apps needed to operate a workspace and a growing set of first-party apps for everyday work. Operators decide which apps are enabled for their users, so availability can differ between instances.</p><p>In the user interface these are <strong>apps</strong>. In the repository and developer documentation they are delivered as <strong>plugins</strong>.</p><h2 id="first-party-sovereign-apps" tabindex="-1">First-party Sovereign apps <a class="header-anchor" href="#first-party-sovereign-apps" aria-label="Permalink to &quot;First-party Sovereign apps&quot;">​</a></h2><h3 id="sovereign-tasks" tabindex="-1">Sovereign Tasks <a class="header-anchor" href="#sovereign-tasks" aria-label="Permalink to &quot;Sovereign Tasks&quot;">​</a></h3><p><strong>Status:</strong> Available</p><p>A privacy-first task manager for personal and shared work. Tasks supports lists, subtasks, notes, due dates, recurrence, favourites, filters, search, manual reordering, bulk actions, and a mobile interface designed around swipeable lists and bottom sheets.</p><p>Tasks uses the Sovereign account and instance database rather than requiring a separate task-service account or deployment.</p><p><a href="https://github.com/sovereignfs/sovereign-tasks" target="_blank" rel="noreferrer">Source: sovereign-tasks</a></p><h3 id="sovereign-shopper" tabindex="-1">Sovereign Shopper <a class="header-anchor" href="#sovereign-shopper" aria-label="Permalink to &quot;Sovereign Shopper&quot;">​</a></h3><p><strong>Status:</strong> Available</p><p>A shared grocery-list app for households and groups. Its current scope includes multiple lists, item suggestions, quantities, per-item icons, editing, purchase recording, and direct list sharing with other users on the instance.</p><p>Shopper demonstrates how a focused collaborative app can reuse Sovereign identity, user selection, notifications, and app-scoped data.</p><p><a href="https://github.com/sovereignfs/sovereign-shopper" target="_blank" rel="noreferrer">Source: sovereign-shopper</a></p><h3 id="sovereign-plainwrite" tabindex="-1">Sovereign Plainwrite <a class="header-anchor" href="#sovereign-plainwrite" aria-label="Permalink to &quot;Sovereign Plainwrite&quot;">​</a></h3><p><strong>Status:</strong> Available</p><p>A Git-backed content editor for Markdown and MDX static sites. Plainwrite covers project membership, GitHub content sync, local drafts, structured frontmatter, autosave, publishing, staged deletion, schema tools, and per-user GitHub credentials stored through Sovereign platform services.</p><p>Plainwrite is an example of a larger domain app using the SDK for identity, secrets, external connections, notifications, activity, portability, and data contracts while keeping its publishing workflow plugin-owned.</p><p><a href="https://github.com/sovereignfs/sovereign-plainwrite" target="_blank" rel="noreferrer">Source: sovereign-plainwrite</a></p><h3 id="sovereign-wallet" tabindex="-1">Sovereign Wallet <a class="header-anchor" href="#sovereign-wallet" aria-label="Permalink to &quot;Sovereign Wallet&quot;">​</a></h3><p><strong>Status:</strong> In development — Phase 1 nearing completion</p><p>A private wallet for loyalty and membership cards, sensitive-document snapshots, and personal financial records. The current Phase 1 work includes the Wallet home and card flows for creating, listing, opening, and displaying QR or barcode-based cards.</p><p>Wallet is not yet presented as generally available. Later sensitive-document features depend on the platform&#39;s storage and client-side encryption contracts and must not be described as shipped until those foundations are ready.</p><p>The Wallet source repository will be linked when it is publicly available.</p><h2 id="core-workspace-apps" tabindex="-1">Core workspace apps <a class="header-anchor" href="#core-workspace-apps" aria-label="Permalink to &quot;Core workspace apps&quot;">​</a></h2><p>These platform apps provide the shared workspace itself:</p><table tabindex="0"><thead><tr><th>App</th><th>Availability</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Launcher</strong></td><td>Available</td><td>The workspace home screen and entry point to installed apps.</td></tr><tr><td><strong>Account</strong></td><td>Available</td><td>Profile, sign-in security, preferences, activity, and data controls.</td></tr><tr><td><strong>Console</strong></td><td>Available to operators</td><td>User, app, instance, and system administration.</td></tr></tbody></table><p>Read the <a href="/plugins/launcher.html">Launcher</a>, <a href="/plugins/account.html">Account</a>, and <a href="/plugins/console.html">Console</a> documentation.</p><h2 id="how-these-appear-in-the-repository" tabindex="-1">How these appear in the repository <a class="header-anchor" href="#how-these-appear-in-the-repository" aria-label="Permalink to &quot;How these appear in the repository&quot;">​</a></h2><p>The platform&#39;s <code>plugins/</code> workspace contains three kinds of plugin source:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/</span></span>
<span class="line"><span>├── launcher/                       built-in workspace app</span></span>
<span class="line"><span>├── account/                        built-in account app</span></span>
<span class="line"><span>├── console/                        built-in operator app</span></span>
<span class="line"><span>├── sovereign-tasks/                first-party app</span></span>
<span class="line"><span>├── sovereign-shopper/              first-party app</span></span>
<span class="line"><span>├── sovereign-plainwrite/           first-party app</span></span>
<span class="line"><span>├── sovereign-wallet/               first-party app under development</span></span>
<span class="line"><span>├── example-basic/                  SDK reference</span></span>
<span class="line"><span>├── example-api/                    public API reference</span></span>
<span class="line"><span>├── example-minimal/                minimal-shell reference</span></span>
<span class="line"><span>├── example-overlay-small/          overlay reference</span></span>
<span class="line"><span>├── example-overlay-medium/         overlay reference</span></span>
<span class="line"><span>├── example-overlay-large/          overlay reference</span></span>
<span class="line"><span>└── example-monetized/              entitlement reference</span></span></code></pre></div><p>First-party apps are maintained in standalone repositories. <code>sovereign.plugins.json</code> declares each app repository and pinned reference that the platform installation workflow composes into the runtime. A developer may use a <code>.local</code> suffix for an editable local checkout, but that suffix is not part of the canonical app or plugin name. The standalone app repository remains authoritative for its manifest, implementation, and release history.</p><p>Example plugins are developer references, not products intended for normal workspace use. They demonstrate SDK sessions, API routes, shell modes, and entitlement behavior.</p><h2 id="build-for-a-custom-need" tabindex="-1">Build for a custom need <a class="header-anchor" href="#build-for-a-custom-need" aria-label="Permalink to &quot;Build for a custom need&quot;">​</a></h2><p>An app is delivered to Sovereign as a plugin. Instead of creating a separate service stack, a developer can use the runtime&#39;s supported contracts for:</p><ul><li>Authentication and the current user session.</li><li>App-scoped database access.</li><li>Shared interface components and workspace navigation.</li><li>Declared storage, notification, job, event, and integration capabilities as those contracts become available.</li><li>Operator-managed installation and access.</li></ul><p><a href="/get-started/developers.html">Start building an app</a></p>`,37)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
